import React, { useEffect, useState } from 'react';
import { Text, View, Button } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as AuthSession from 'expo-auth-session';
import jwtDecode from 'jwt-decode';

const auth0ClientId = 'your_client_id';
const authorizationEndpoint = 'your_authorization_endpoint';
const tokenEndpoint = 'your_token_endpoint';
const auth0ClientSecret = 'your_client_secret';

export default function App() {
  const [name, setName] = useState(null);

  const handleLogin = async () => {
    const redirectUri = AuthSession.makeRedirectUri({ useProxy: true });
    const result = await AuthSession.startAsync({
      authUrl:
        `${authorizationEndpoint}?` +
        `&client_id=${auth0ClientId}` +
        `&client_secret=${auth0ClientSecret}` +
        `&redirect_uri=${encodeURIComponent(redirectUri)}` 
    });

    if (result.type === 'success') {
      setName(result.params.name);
      await AsyncStorage.setItem('userToken', result.params.access_token);

      refreshToken();
    }
  };

  const refreshToken = async () => {
    const userToken = await AsyncStorage.getItem("userToken");
    const decoded = jwtDecode(userToken);

    const diff = decoded.exp - new Date().getTime() / 1000;

    if (diff < 30) {
      const result = await fetch(tokenEndpoint, {
        method: 'POST',
        headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
        body: `grant_type=refresh_token&client_id=${auth0ClientId}&client_secret=${auth0ClientSecret}&refresh_token=${userToken}`,
      });

      if (result.ok) {
        await AsyncStorage.setItem('userToken', result.json().access_token);
        setName(result.params.name);
      }
    }

    setTimeout(refreshToken, (diff - 10) * 1000);
  };

  useEffect(() => {
    handleLogin();
  }, []);

  return (
    <View>
      <Text>{name ? `Hello ${name}!` : 'Welcome to the app.'}</Text>
      <Button title="Login" onPress={handleLogin} />
    </View>
  );
}